const Q_ECONOMICS_2014=[{"id": "objective>Economics>2014>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What subject is this?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Commerce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Economics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mathematics</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject is indicated in the question is Economics.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2014>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The choice of how to produce in a command economy is determined by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrialists</div>", "<div style=\"font-family:Cambria;font-size:17px;\">labour unions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A command economy is a system where the government, rather than the free market, determines what goods should be produced, how much should be produced, and the price at which the goods are offered for sale. It also determines investments and incomes. The command economy is a key feature of any communist society.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>2014>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In capitalist economies, questions about what to produce are ultimately answered by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Available technical skills in the economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Output decision of firms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Holding decisions of households</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Income level of households</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capitalism is an economic system in which private individuals or businesses own capital goods. The production of goods and services is based on supply and demand in the general market—known as a market economy—rather than through central planning—known as a planned economy or command economy.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>2014>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best measure of dispersion to determine the tallest tree in a forest is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Variance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Standard deviation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mean deviation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Range</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The range is the best measure of dispersion to determine the tallest tree in a forest. The range is the difference between the highest and lowest values in a set of data. In this case, it would be the difference between the height of the tallest and shortest tree. The other options, variance, standard deviation, and mean deviation, are measures of dispersion that provide information about the spread of data around the mean, not the extreme values.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2014>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><p style=\"padding: 3px;\">Use the pie chart below to answer the question that follows</p>  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> What is the percentage contribution of services to the national income?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">54%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15%</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Let x represent services <br/>  <br/> Services = 360-(x + 72 + 108 + 126)= 54° <br/>  <br/> Percentage contribution = 54/360 x 100  <br/>                                                   = 15%</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2014>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <p style=\"padding: 3px;\">Use the pie chart below to answer the question that follows</p>  <br/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> If the national income is ₦60m, the contribution of the manufacturing sector is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦9m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦18m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦17m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦12m</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturing contribution = 108/360 x ₦60m  <br/> = ₦18m</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2014>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> A combination of factors responsible for a shift from D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span>  to D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>  are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Price of the commodity and weather conditions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Consumers income and population size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Consumers taste and change in price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Consumers' income and change in technology</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The points from D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> to D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> implies increase in demand and this could be caused by increase in consumer's income or population size, effective advertising etc.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2014>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that Qd = 40-2p and Qs = 6p + 24, calculate the equilibrium price.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦36</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦16</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦4</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equilibrium Price is Qd = Qs  <br/>  40 - 2p = 6P + 24  <br/>  40 - 24 = 6P + 2P  <br/>  16 = 8P  <br/>  P = ₦2</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2014>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A change in demand for a normal good implies that, there is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Shift in the demand curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Movement along a given demand curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Change in the price elasticity of demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Change in the quantity demanded as price change</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A normal good is a good that experiences an increase in its demand due to a rise in consumers' income. In other words, if there's an increase in wages, demand for normal goods increases while conversely, wage declines or layoffs lead to a reduction in demand.</div>", "topic": "THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND"}, {"id": "objective>Economics>2014>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a 10% rise in price causes a 5% decrease in the quantity demanded of a commodity, the elasticity of demand is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Zero elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Elastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Inelastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Unitary elastic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">e = % change in quantity demanded/ % change in price <br/>                       e = 5/10 <br/>                              e = 0.5. It is inelastic because an increase in price leads to fall in the quantity demanded</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2014>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/> From the graph above, the consumer will attain equilibrium at point </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">L</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">J</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The consumer attains equilibrium at point K which is higher than J and M. This is the point of optimal satisfaction for the consumer where the indifference curve is tangential to the budget line.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : CONSUMER EQUILIBRIUM"}, {"id": "objective>Economics>2014>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rightward shift of the budget line is caused by a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Change in consumer taste</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fall in the commodity relative price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rise in the commodity relative price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fall in consumer income</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fall in the commodity's price increase the consumer's purchasing power which is represented by a rightward shift in the budget line</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : BUDGET LINE"}, {"id": "objective>Economics>2014>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given the supply function  P=<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4</span>(Qs+10) and P=₦10 what is Qs?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">(Qs</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">10)</td></tr></table></div>  <br/>  P = 10   <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />4</td><td style=\"text-align:center;\">(Qs</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">10)</td></tr></table></div>  <br/>  40 = Qs + 10  <br/>  Qs = 40 - 10  <br/>  = 30units</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2014>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Price (₦)</td><td style=\"border:1px solid black;text-align:center;\"> Quantity Supplied <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">8</td><td style=\"border:1px solid black;text-align:center;\">20 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">10</td><td style=\"border:1px solid black;text-align:center;\">24</td></tr></table></div> <br/> From the table above, calculate the price elasticity of supply</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.80</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.25</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%</td><td style=\"text-align:center;\">Δ</td><td style=\"text-align:center;\">Qs</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">24 - 20<hr size=\"1\" />20</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div>   <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4<hr size=\"1\" />20</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%</td><td style=\"text-align:center;\">Δ</td><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10 - 8<hr size=\"1\" />8</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td><td style=\"text-align:center;\"> <br/>   =</td><td style=\"text-align:center;\">2<hr size=\"1\" />8</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">25</td></tr></table></div> <br/>  P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">ES</span> = 20/25 = 0.80</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2014>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When price is set below equilibrium this will lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">A new equilibrium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in the quantity supplied</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A fall in price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the quantity supplied</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When the price is set below the equilibrium,there will be excess demand over supply which will lead to shortage.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2014>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Price mechanism determines the price of commodities through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Market forces</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The sales of treasury bills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Government legislation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Auctioning</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The price mechanism is an economic concept that refers to the way the supply and demand of a commodity or service interact to determine its price. This is done through market forces, which include the behaviors of buyers and sellers. Therefore, the correct answer is 'Market forces'.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE"}, {"id": "objective>Economics>2014>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Unity of labour</td><td style=\"border:1px solid black;text-align:center;\"> Total Product</td><td style=\"border:1px solid black;text-align:center;\"> Average Product</td><td style=\"border:1px solid black;text-align:center;\"> Marginal Product <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">8</td><td style=\"border:1px solid black;text-align:center;\">8</td><td style=\"border:1px solid black;text-align:center;\"> - <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">20</td><td style=\"border:1px solid black;text-align:center;\">10</td><td style=\"border:1px solid black;text-align:center;\">12 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3</td><td style=\"border:1px solid black;text-align:center;\">E</td><td style=\"border:1px solid black;text-align:center;\">9</td><td style=\"border:1px solid black;text-align:center;\">7 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">4</td><td style=\"border:1px solid black;text-align:center;\">28</td><td style=\"border:1px solid black;text-align:center;\">7</td><td style=\"border:1px solid black;text-align:center;\">F <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">5</td><td style=\"border:1px solid black;text-align:center;\">40</td><td style=\"border:1px solid black;text-align:center;\">8</td><td style=\"border:1px solid black;text-align:center;\">12</td></tr></table></div> <br/> From the table above, find the values of E and F respectively.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">68 and 12</div>", "<div style=\"font-family:Cambria;font-size:17px;\">28 and 5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12 and 19</div>", "<div style=\"font-family:Cambria;font-size:17px;\">27 and 1</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For E: TP = AP × Q  <br/>  = 9 × 3 = 27  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">For</td><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">:</td><td style=\"text-align:center;\">MP</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ΔTP<hr size=\"1\" />ΔQ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">28 - 27<hr size=\"1\" />4-3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1</td></tr></table></div> <br/>  (E, F) = 27 and 1</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCTION FUNCTIONS & LAWS OF RETURNS"}, {"id": "objective>Economics>2014>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the production cost of a large firm is higher than that of a small firm, it is experiencing</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">External diseconomies of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Internal economies of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Internal diseconomies of scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">External economies of scale</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the production cost of a large firm is higher than that of a small firm, it is experiencing internal diseconomies of scale. Diseconomies of scale occur when a business grows so large that the costs per unit increase. It takes place when economies of scale no longer function for a firm. With this increase in output, the cost per unit output increases. It is the result of inefficiency in the firm.</div>", "topic": "THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION"}, {"id": "objective>Economics>2014>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Division of labour requires that, the tasks in a production line be performed</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">In stages </div>", "<div style=\"font-family:Cambria;font-size:17px;\">By all workers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">By unskilled labourers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">By specialists</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Division of labor can be defined simply as the splitting or separation of a particular work process into various processes such that each process is undertaken by a different worker or different group of workers. Division of labour is done in stages. </div>", "topic": "THEORY OF PRODUCTION (1) : DIVISION OF LABOUR & SPECIALISATION"}, {"id": "objective>Economics>2014>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that FC = ₦500,VC=N1500 and Q = 50 units, find the average cost of the product.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦10</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦30</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">AC</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">TC<hr size=\"1\" />Q</td></tr></table></div>  <br/>  TC = FC + VC  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Hence:</td><td style=\"text-align:center;\">AC</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">FC+VC<hr size=\"1\" />Q</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">500+1500<hr size=\"1\" />50</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2000<hr size=\"1\" />50</td></tr></table></div> <br/>  = ₦40</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2014>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rent and administrative expenses are examples of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Average variable cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fixed cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Variable cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Average fixed cost </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rent and administrative expenses are examples of fixed costs. Fixed costs are costs that do not change with the level of output. They are incurred even when the firm is not producing anything. They include costs like rent, salaries, and administrative expenses.</div>", "topic": "THE CONCEPT OF COST & REVENUE : EXPLICIT AND IMPLICIT COSTS"}, {"id": "objective>Economics>2014>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A perfect competitor will continue to expand output up to the point where</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MR=AR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC< MR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC>MR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">TC>TR</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A perfect competitor will continue to expand output up to the point where Marginal Revenue (MR) equals Average Revenue (AR). This is because in perfect competition, the price is given and constant, hence, the average revenue, which is also the price, equals the marginal revenue.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2014>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the characteristics of a monopolist is that, he can influence</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Prices charged by other producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both price and quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Price or quantity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Quantity produced by other producers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The monopolist can either influence price or quantity but it cannot influence both. Before a monopolist will charge or influence his price, he has to look at his elasticity.  <br/> </div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2014>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Monopolist can boost his revenue by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Reducing total output to march the price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increasing price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reducing price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adjusting both price and output upward</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A monopolist is a firm that has no close competitors and faces a downward-sloping demand curve. This means that the monopolist can set the price of its output, and the quantity demanded will decrease as the price increases. <br/>  <br/> If a monopolist increases the price of its output, its total revenue will increase, even if the quantity demanded decreases. This is because the increase in price will outweigh the decrease in quantity demanded.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2014>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following can be used to measure the Gross National Product in an open economy?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C+I+G+X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C+I+G</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C+I+G+(X-M)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C+I+G+(X+M)</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For an open economy, GNP is calculated as: C+I+G+(X-M) where C = consumption expenditure, I= investment expenditure  G = government expenditures  X = exports  and M =imports.</div>", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME"}, {"id": "objective>Economics>2014>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If MPC = 2/3 and investment is ₦100 million. The level of national income is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦10 Million </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦303 million </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦300 Million </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦100 million</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">MPC = 2/3 <br/>  <br/> Since K = 1/1 - MPC <br/> Then, K = 1 / 1 - 2/3 <br/> = 3 <br/>  <br/>  Y = K x  Δ I = 3 x 100  <br/>  = ₦300m</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : THE CONCEPT OF MULTIPLIER"}, {"id": "objective>Economics>2014>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The precautionary demand for money is determined by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The level of savings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The level of income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">General price level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The rate of interest</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The precautionary demand for money depends upon the level of income ( i.e direct) , and business activity, opportunities for unexpected profitable deals, availability of cash, the cost of holding liquid assets in bank reserves, etc. Keynes held that the precautionary demand for money, like transactions demand, was a function of the level of income.</div>", "topic": "MONEY : DEMAND FOR MONEY"}, {"id": "objective>Economics>2014>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An inflation that co-exists with high rate of unemployment is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Stagflation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Demand-pull inflation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cost-push inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hyperinflation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is a situation when an economy is facing the twin macroeconomic problems of inflation and unemployment or inflation with stagflation.</div>", "topic": "INFLATION & DEFLATION : TYPES"}, {"id": "objective>Economics>2014>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the challenges facing the banking industry in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Providing employment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Providing loans for investment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Creating more money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ensuring technological security</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major challenges facing the banking industry in Nigeria is ensuring technological security. With the advent of digital banking, ensuring the security of customers' data and transactions has become a major concern. This includes protecting against cyber attacks, fraud, and other forms of financial crime.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2014>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Short-terms loans for investment are usually obtained through the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Development bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Money market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Capital market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stock market</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The money market deals with short term loans in contrary to the capital market which deals with medium and long term loans.</div>", "topic": "FINANCIAL INSTITUTION : DEVELOPMENT, MERCHANT, MORTGAGE BANK ETC"}, {"id": "objective>Economics>2014>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given a base year and price index of 175% the following year. Which of the following will arise</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The cost leaving remains unchanged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The value of money rise by 75%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The value of money falls by 75%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The cost of living decreases in that year</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This implies that the cost of living (i.e price) has risen by 75% and consequently, the value of money will also fall by the same 75%. The value of money and price index is inversely related.</div>", "topic": "INFLATION & DEFLATION : EFFECT"}, {"id": "objective>Economics>2014>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Wage freeze is a policy measure aimed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Curbing inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Regulating standard of living</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Curbing deflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Encouraging investors</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wage freeze is a policy measure that is often used to curb inflation. Inflation is a general increase in prices and fall in the purchasing value of money. When wages are frozen, it means that there will be no increase in salaries for a period of time. This can help to slow down the rate of inflation because when wages increase, people have more money to spend, which can drive up prices. Therefore, by freezing wages, the government can help to control the rate of inflation.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2014>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major obstacle for the development of Nigerian economy is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rural-urban migration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Over dependence on oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Poor developmental policies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low capital formation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Over dependence on oil is a major obstacle for the development of the Nigerian economy. This is because the Nigerian economy is heavily reliant on oil exports for its revenue. When oil prices are high, the economy does well. However, when oil prices fall, the economy suffers. This over reliance on oil makes the economy vulnerable to fluctuations in oil prices. Diversifying the economy and reducing dependence on oil would help to make the economy more resilient.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2014>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major feature of underdeveloped economy is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Low rate of population growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low level of standard of living </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low level of unemployment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Excess capacity utilization </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The features or characteristics of an underdeveloped economy or country is: <br/> - dependence on agriculture <br/> - high dependency on foreign nations <br/> - low savings and investment <br/> - population explosion <br/> - low per capita income <br/> - low standard of living <br/> - high deatn rate <br/> - high level of illiteracy <br/> - high level of unemployment <br/> - low rate of economic growth</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2014>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important role of Agriculture in Nigeria's economy development is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Regulation of price system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Provision of infrastructure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Provision of employment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Processing of raw materials for industries</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It helps to maintain a healthy and peaceful population and also a source of food and nutrition for households. In Nigeria, agriculture exports have played an important role in economic development by providing the needed foreign exchange earnings and also It helps to generate employment opportunities for the unemployed youths.</div>", "topic": "AGRICULTURE IN WEST AFRICA : ROLES"}, {"id": "objective>Economics>2014>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An advantage of large-scale farming over peasant farming is in the area of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Redistribution national income to various regions of the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Encouraging the use of traditional implements</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Encouraging urban-rural migration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Providing research and massive employment of labour</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The benefit of large scale farming over peasant farming is the reduced cost of food. Consolidation and vertical coordination have not only reduced costs, but also expanded diversity of food products and solved information problems. Due to its extensive operations, it encourages research and allows massive employment of labour.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2014>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major disadvantage of localization of industry is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Over-utilization of installed industrial capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The risk of seasonal unemployment </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Under-utilisation of installed industrial capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The risk of structural unemployment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Localization of industry often leads to a concentration of similar businesses in a specific area. While this can create a strong local economy and specialization, it also makes the area more vulnerable to economic shifts and changes in demand for the specific industry. If the localized industry declines or becomes obsolete, it can result in structural unemployment, where workers' skills are no longer in demand and they may find it difficult to find new employment in the same area without retraining.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2014>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One major factor that determined the location of industry is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Its proximity to the market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The capital base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The social responsibility of the firm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tax exemption grant</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Proximity to market is a major factor that determines industry location. Others includes: proximity to source of raw materials, availability of capital, nearness to source of power, availability of labour, adequate transport network, political stability, favourable climate etc.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2014>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major contribution of OPEC to the Nigeria economy is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Granting of subsidies on petroleum products</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Stabilization of oil price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Building of refineries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Provision of social infrastructures</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">OPEC aims to regulate the supply of oil in order to set the price on the world market. Stabilization of oil price is a major contribution of OPEC to the Nigerian economy.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : OPEC"}, {"id": "objective>Economics>2014>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The loading of crude oil at the terminal is an activity in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Upstream and downstream sector of the oil industry.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Upstream sector of the oil industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Midstream and upstream sectors of the oil industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Downstream sectors of the oil industry</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The loading of crude oil at the terminal is an activity in the midstream sector of the oil industry. The oil and gas industry is usually divided into three major sectors: upstream, midstream, and downstream. The upstream sector involves exploration and production, the midstream sector involves transportation, storage, and wholesale marketing, while the downstream sector involves refining and selling. Therefore, the loading of crude oil at the terminal falls under the midstream sector, which involves transportation and storage.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : ONSHORE & OFFSHORE OF THE OIL SECTOR"}, {"id": "objective>Economics>2014>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The short-run average variable cost of a firm will rise owing to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The building of new warehouses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the cost of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An increase in the salaries of directors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The expansion of factory space</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If the average cost falls due to an increase in the output, the marginal cost is less than the average cost. <br/> If the average cost rises due to an increase in the output, the marginal cost is more than the average cost.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2014>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Firms embark on vertical integration in order to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Prevent other firm from entry the market </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reduce advertisement and marketing cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Enjoy economies of large scale production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Take over markets formally controlled by other firms</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vertical integration is a strategy whereby a company owns or controls its suppliers, distributors, or retail locations to control its value or supply. The following are some of the reasons for vertical integration: <br/> Reduce transportation costs if common ownership results in closer geographic proximity. <br/> Improve supply chain coordination. <br/> Provide more opportunities to differentiate by means of increased control over inputs. <br/> Capture upstream or downstream profit margins.</div>", "topic": "BUSINESS ORGANISATION : INTRODUCTION"}, {"id": "objective>Economics>2014>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The voting power in co-operative societies is vested on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Member  with loan </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The shareholders </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Members with the highest contribution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The management</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In co-operative societies, the voting power is vested on the shareholders. This is because co-operative societies are owned and controlled by their members, who have equal voting rights (one member, one vote) regardless of their level of financial contribution. This is different from other types of companies where voting power is often tied to the number of shares a person holds.</div>", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES"}, {"id": "objective>Economics>2014>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An accurate census figure is an important tool for planning in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Siting industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Providing social amenities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Allocating resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Providing employment</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An accurate census figure is crucial for planning in resource allocation. Census data provides detailed information about the population, including age, sex, occupation, and location. This information is used by the government to allocate resources effectively and efficiently. For example, if the census data shows a high number of school-age children in a particular area, the government can allocate more resources to education in that area.</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>2014>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An accurate population census is important in order to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Provide employment  opportunities for the people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Estimate a country's per-capita income</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fast tract industrial development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Produce more food for growing population</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Population census data is needed to guide the planning and development processes in a country. The importance of census as a specific type of accurate statistics of the population characteristics and social trends is the basis for the successful development of a country.This is important as the per-capita income is arrived at by dividing the national income with the population</div>", "topic": "POPULATION : INTRODUCTION"}, {"id": "objective>Economics>2014>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major determinant of a floating exchange rate is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">An Act of the parliament </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The system of government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The forces of demand and supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The highest denomination of a currency</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A floating exchange rate is a regime where the currency price of a nation is set by the forex market based on supply and demand relative to other currencies. This is in contrast to a fixed exchange rate, in which the government entirely or predominantly determines the rate.</div>", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE"}, {"id": "objective>Economics>2014>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the importation of a commodity is limited to a definite quantity, the trade control measure imposed is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Import duties </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Quotas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tariff</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Excise duties</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">quotas; a limited quantity of a particular product which under official controls can be produced, exported, or imported.</div>", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE"}, {"id": "objective>Economics>2014>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main objective of WTO is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Provide a mechanism for tariff reduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Assist countries with chronic balance of payments problem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Assist developing countries to execute developmental project</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ensure adequate protection for infant industry</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The main objective of the World Trade Organization (WTO) is to provide a mechanism for tariff reduction. The WTO is an international organization that deals with the global rules of trade between nations. Its main function is to ensure that trade flows as smoothly, predictably, and freely as possible. This is achieved by providing a mechanism for tariff reduction, which helps to eliminate or reduce trade barriers, such as tariffs, and to facilitate open trade.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : IBRD, AFDB, UNCTAD ETC"}, {"id": "objective>Economics>2014>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major determinant of the total volume of output in an economy is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Composition of the consumer spending </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Number of farmer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Size of the labour force</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Level of the total expenditure</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major determinant of the total volume of output in an economy is the size of the labour force. The size of the labour force determines the amount of goods and services that can be produced. If the labour force is large, more goods and services can be produced, leading to a higher total volume of output. The other options, such as the composition of consumer spending, the number of farmers, and the level of total expenditure, can influence the type of goods and services produced, but they do not directly determine the total volume of output.</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>2014>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The labour force of the a country is determined by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Geographical distribution of the population </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sex distribution of the population </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Number of people available for work</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Age structure of the population       </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The labour force of a country is determined by the number of people available for work. This includes those who are currently employed and those who are unemployed but seeking work. The geographical distribution, sex distribution, and age structure of the population can influence the size and composition of the labour force, but they do not directly determine it.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : SUPPLY OF LABOUR"}];
